#!/bin/bashset -e# NICTO Minecraft Server Deployment on AWS EC2# Usage: bash deploy_minecraft.sh [instance-type]# Default: t4g.medium (free-tier eligible)INSTANCE_TYPE="${1:-t4g.medium}"KEY_NAME="nikto-minecraft"SECURITY_GROUP="minecraft-sg"INSTANCE_NAME="NICTO-Minecraft"echo "=== NICTO Minecraft Server Deployment ==="# 1. Create security groupecho "[1/6] Creating security group..."SG_ID=$(aws ec2 create-security-group --group-name $SECURITY_GROUP --description "Minecraft server" --query 'GroupId' --output text 2>/dev/null ||          aws ec2 describe-security-groups --group-names $SECURITY_GROUP --query 'SecurityGroups[0].GroupId' --output text)aws ec2 authorize-security-group-ingress --group-id "$SG_ID" --protocol tcp --port 22 --cidr 0.0.0.0/0 2>/dev/null || trueaws ec2 authorize-security-group-ingress --group-id "$SG_ID" --protocol tcp --port 25565 --cidr 0.0.0.0/0 2>/dev/null || true# 2. Create key pairecho "[2/6] Creating key pair..."aws ec2 create-key-pair --key-name "$KEY_NAME" --query 'KeyMaterial' --output text > "${KEY_NAME}.pem"chmod 400 "${KEY_NAME}.pem"# 3. Launch EC2 instance (Ubuntu 24.04 ARM)echo "[3/6] Launching EC2 instance..."UBUNTU_AMI=$(aws ec2 describe-images --owners 099720109477 --filters "Name=name,Values=ubuntu/images/hvm-ssd-gp3/ubuntu-noble-24.04-arm64-server-*" "Name=state,Values=available" --query 'Images[0].ImageId' --output text)INSTANCE_ID=$(aws ec2 run-instances \  --image-id "$UBUNTU_AMI" \  --instance-type "$INSTANCE_TYPE" \  --key-name "$KEY_NAME" \  --security-group-ids "$SG_ID" \  --tag-specifications "ResourceType=instance,Tags=[{Key=Name,Value=$INSTANCE_NAME}]" \  --query 'Instances[0].InstanceId' --output text)echo "  Instance: $INSTANCE_ID ($INSTANCE_TYPE)"# 4. Wait for instanceecho "[4/6] Waiting for instance to be ready..."aws ec2 wait instance-running --instance-ids "$INSTANCE_ID"PUBLIC_IP=$(aws ec2 describe-instances --instance-ids "$INSTANCE_ID" --query 'Reservations[0].Instances[0].PublicIpAddress' --output text)echo "  Public IP: $PUBLIC_IP"# 5. SSH and install Minecraftecho "[5/6] Installing Minecraft server..."ssh -o StrictHostKeyChecking=no -i "${KEY_NAME}.pem" "ubuntu@$PUBLIC_IP" << 'REMOTE'  sudo apt-get update -qq  sudo apt-get install -y -qq openjdk-21-jre-headless tmux curl  mkdir -p ~/minecraft  cd ~/minecraft  curl -sLO https://piston-data.mojang.com/v1/objects/4707d00eb834b446675d6a30e5c5f11e2a1b2f88/server.jar  echo "eula=true" > eula.txt  chmod +x server.jar  echo "max-players=20" >> server.properties  echo "motd=NICTO Minecraft Server" >> server.properties  echo "online-mode=false" >> server.properties  tmux new-session -d -s minecraft 'java -Xmx2G -Xms1G -jar server.jar nogui' 2>/dev/null || \    java -Xmx2G -Xms1G -jar server.jar nogui &REMOTE# 6. Output connection infoecho "[6/6] Deployment complete!"echo "================================"echo "Server IP: $PUBLIC_IP"echo "Connect: minecraft://$PUBLIC_IP:25565"echo "SSH: ssh -i ${KEY_NAME}.pem ubuntu@$PUBLIC_IP"echo "================================"